using System.Net;
using System.Net.Http;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.HttpOverrides;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Http;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Changed from AddSingleton to AddScoped: a singleton capturing a scoped service
// is a captive dependency. .NET 9 enables ValidateScopes in development by default
// and will throw InvalidOperationException at startup.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// .NET 9: HttpClientFactory now uses SocketsHttpHandler as the default primary
// handler. Casting to HttpClientHandler throws InvalidCastException.
// Fix: use ConfigurePrimaryHttpMessageHandler with SocketsHttpHandler.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });
// .NET 9: ForwardedHeadersMiddleware silently ignores X-Forwarded-* headers from
// proxies not in KnownProxies or KnownNetworks. Add your reverse proxy address.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
